/* ---------- ユーティリティ ---------- */
function shuffle(arr, rnd) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor((rnd ? rnd() : Math.random()) * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function ri(min, max) { return min + Math.floor(Math.random() * (max - min + 1)); }
function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
function numChoices(ans, spread) {
  const s = new Set([ans]);
  let guard = 0;
  while (s.size < 4 && guard++ < 200) {
    const d = ans + (Math.random() < 0.5 ? -1 : 1) * ri(1, spread);
    if (d >= 0 && d !== ans) s.add(d);
  }
  while (s.size < 4) s.add(ans + s.size * 2 + 1);
  return shuffle([...s]).map(String);
}
function gcd(a, b) { return b ? gcd(b, a % b) : a; }
function fracStr(n, d) { const g = gcd(n, d); return `${n / g}/${d / g}`; }

/* ---------- 算数 問題生成器 ----------
   level: 1=初級 2=標準 3=応用 4=発展 */
const GEN = {
  count20(lv) { const n = ri(3, lv >= 2 ? 20 : 10); return { q: `●が ${n}こ あります。すうじで かくと？`, t: 'choice', c: numChoices(n, 3), a: String(n), e: `こえに だして かぞえて みよう。こたえは ${n} だよ。` }; },
  add_nc(lv) { let a, b; do { a = ri(1, lv >= 2 ? 9 : 5); b = ri(1, 9 - a); } while (false); return { q: `${a} + ${b} = ？`, t: 'choice', c: numChoices(a + b, 3), a: String(a + b), e: `${a}と${b}を あわせると ${a + b} だよ。` }; },
  sub_nb(lv) { const a = ri(2, lv >= 2 ? 9 : 6), b = ri(1, a - 1); return { q: `${a} − ${b} = ？`, t: 'choice', c: numChoices(a - b, 3), a: String(a - b), e: `${a}から ${b}を とると ${a - b} だよ。` }; },
  add_c(lv) { const a = ri(lv >= 3 ? 5 : 6, 9), b = ri(11 - a, 9); return { q: `${a} + ${b} = ？`, t: 'choice', c: numChoices(a + b, 4), a: String(a + b), e: `${a}に ${10 - a}を たして10。のこりの ${b - (10 - a)}を たして ${a + b}。` }; },
  sub_b(lv) { const a = ri(11, 18), b = ri(a - 9, 9); return { q: `${a} − ${b} = ？`, t: 'choice', c: numChoices(a - b, 4), a: String(a - b), e: `10から ${b}を ひいて ${10 - b}。のこりの ${a - 10}と あわせて ${a - b}。` }; },
  count100(lv) { const t = ri(2, 9), o = ri(0, 9); const n = t * 10 + o; return { q: `10が ${t}こと 1が ${o}こで、いくつ？`, t: 'choice', c: numChoices(n, 12), a: String(n), e: `10が${t}こで${t * 10}。それに ${o}を たして ${n} だよ。` }; },
  add_sub_2d(lv) {
    if (Math.random() < 0.5) { const a = ri(11, lv >= 2 ? 89 : 49), b = ri(11, 99 - a); return { q: `${a} + ${b} = ？（ひっ算で 考えよう）`, t: 'input', a: String(a + b), e: `一のくらいから 計算。こたえは ${a + b}。` }; }
    const a = ri(30, 99), b = ri(11, a - 10); return { q: `${a} − ${b} = ？（ひっ算で 考えよう）`, t: 'input', a: String(a - b), e: `くり下がりに 気をつけて。こたえは ${a - b}。` };
  },
  kuku(lv) { const a = ri(lv >= 2 ? 2 : 2, 9), b = ri(2, 9); return { q: `${a} × ${b} = ？`, t: 'choice', c: numChoices(a * b, Math.max(3, a)), a: String(a * b), e: `${a}のだん：${a}×${b}=${a * b}。` }; },
  length_cm(lv) {
    if (Math.random() < 0.5) { const c = ri(1, 9), m = ri(1, 9); return { q: `${c}cm${m}mm は 何mm？`, t: 'choice', c: numChoices(c * 10 + m, 10), a: String(c * 10 + m), e: `1cm=10mm。${c}cm=${c * 10}mm、あわせて ${c * 10 + m}mm。` }; }
    const a = ri(2, 9) * 10; return { q: `${a}mm は 何cm？`, t: 'choice', c: [String(a / 10), String(a), String(a / 10 + 1), String(a * 10)], a: String(a / 10), e: `10mm=1cm だから ${a}mm=${a / 10}cm。` };
  },
  count1000(lv) { const h = ri(1, 9), t = ri(0, 9), o = ri(0, 9); const n = h * 100 + t * 10 + o; return { q: `100が ${h}こ、10が ${t}こ、1が ${o}こ。あわせて いくつ？`, t: 'input', a: String(n), e: `${h * 100}+${t * 10}+${o}=${n} だよ。` }; },
  div_basic(lv) { const b = ri(2, 9), q = ri(2, 9); const a = b * q; if (lv >= 3 && Math.random() < 0.4) { const r = ri(1, b - 1); return { q: `${a + r} ÷ ${b} の あまりは？（商は ${q}）`, t: 'choice', c: numChoices(r, 2), a: String(r), e: `${b}×${q}=${a}。${a + r}−${a}=${r} あまり${r}。` }; } return { q: `${a} ÷ ${b} = ？`, t: 'choice', c: numChoices(q, 3), a: String(q), e: `${b}×${q}=${a} だから、こたえは ${q}。` }; },
  mul_2d1d(lv) { const a = ri(lv >= 2 ? 12 : 11, lv >= 3 ? 99 : 49), b = ri(2, 9); return { q: `${a} × ${b} = ？（筆算で 考えよう）`, t: 'input', a: String(a * b), e: `一のくらいから じゅんに かけて、こたえは ${a * b}。` }; },
  big_man(lv) { const m = ri(1, 9), s = ri(0, 9); const n = m * 10000 + s * 1000; return { q: `${n.toLocaleString('ja-JP')} の 読み方で 正しいのは？`, t: 'choice', c: shuffle([`${m}万${s ? s + '千' : ''}`, `${m}千${s}百`, `${m}億${s ? s + '万' : ''}`, `${m}${s}万`]), a: `${m}万${s ? s + '千' : ''}`, e: `一・十・百・千・万。${n.toLocaleString('ja-JP')}は ${m}万${s ? s + '千' : ''}だよ。` }; },
  dec_add_sub(lv) { const a = ri(1, 9), b = ri(1, 9); if (Math.random() < 0.5) return { q: `0.${a} + 0.${b} = ？`, t: 'input', a: (a + b) / 10 + '', e: `0.1が ${a + b}こ分 → ${(a + b) / 10}。` }; const x = Math.max(a, b), y = Math.min(a, b); return { q: `0.${x} − 0.${y} = ？`, t: 'input', a: (x - y) / 10 + '', e: `0.1が ${x - y}こ分 → ${(x - y) / 10}。` }; },
  frac_same(lv) { const d = ri(3, 9); const a = ri(1, d - 2), b = ri(1, d - 1 - a); return { q: `${a}/${d} + ${b}/${d} = ？（分数は「3/5」のように 書こう）`, t: 'input', a: `${a + b}/${d}`, e: `分母が同じなら 分子どうしを たす。${a}+${b}=${a + b} → ${a + b}/${d}。` }; },
  km_m(lv) { if (Math.random() < 0.5) { const k = ri(1, 5), m = ri(1, 9) * 100; return { q: `${k}km${m}m は 何m？`, t: 'input', a: String(k * 1000 + m), e: `1km=1000m。${k * 1000}+${m}=${k * 1000 + m}m。` }; } const s = ri(1, 5); return { q: `${s}分 = 何秒？`, t: 'choice', c: numChoices(s * 60, 30), a: String(s * 60), e: `1分=60秒 だから ${s}×60=${s * 60}秒。` }; },
  big_oku(lv) { const o = ri(1, 9), m = ri(1, 9); return { q: `${o}億は ${m}千万の 何倍…ではなく、1億は 1万の 何倍？`, t: 'choice', c: shuffle(['10000倍', '1000倍', '100倍', '100000倍']), a: '10000倍', e: '万の 10000倍が 億。億の 10000倍が 兆だよ。' }; },
  div_long(lv) { const b = ri(2, lv >= 3 ? 19 : 9), q = ri(11, 99); const a = b * q; return { q: `${a} ÷ ${b} = ？（筆算で 考えよう）`, t: 'input', a: String(q), e: `たてる→かける→ひく→おろす。こたえは ${q}。` }; },
  round(lv) { const n = ri(1000, 9999); const r = Math.round(n / 100) * 100; return { q: `${n} を 四捨五入して 百のくらいまでの がい数に すると？`, t: 'choice', c: shuffle([String(r), String(Math.floor(n / 100) * 100 === r ? r + 100 : Math.floor(n / 100) * 100), String(r + 1000), String(Math.round(n / 1000) * 1000)].filter((v, i, ar) => ar.indexOf(v) === i).concat([String(r - 1000)]).slice(0, 4)), a: String(r), e: `十のくらいが ${Math.floor(n / 10) % 10} だから ${Math.floor(n / 10) % 10 >= 5 ? '切り上げ' : '切り捨て'}て ${r}。` }; },
  dec_mul(lv) { const a = ri(11, 99) / 10, b = ri(2, 9); const ans = Math.round(a * b * 10) / 10; return { q: `${a} × ${b} = ？`, t: 'input', a: String(ans), e: `${a * 10}×${b}=${a * 10 * b}。小数点を 1つ 左に うって ${ans}。` }; },
  area_rect(lv) { const a = ri(2, 12), b = ri(2, 12); return { q: `たて${a}cm、よこ${b}cmの 長方形の 面積は？（数だけ 答えよう・単位cm²）`, t: 'input', a: String(a * b), e: `面積=たて×よこ=${a}×${b}=${a * b}cm²。` }; },
  dec_mul_dec(lv) { const a = ri(11, 39) / 10, b = ri(11, 29) / 10; const ans = Math.round(a * b * 100) / 100; return { q: `${a} × ${b} = ？`, t: 'input', a: String(ans), e: `${a * 10}×${b * 10}=${a * 10 * b * 10}。小数点以下は あわせて2けた → ${ans}。` }; },
  mult_div_isor(lv) {
    if (Math.random() < 0.5) { const n = pick([2, 3, 4, 5, 6, 7, 8, 9]); const k = ri(2, 6); return { q: `${n}の倍数は どれ？`, t: 'choice', c: shuffle([String(n * k), String(n * k + 1), String(n * k - 1), String(n * k + (n > 2 ? Math.floor(n / 2) : 3))].filter((v, i, ar) => ar.indexOf(v) === i)).slice(0, 4), a: String(n * k), e: `${n}×${k}=${n * k} だから ${n * k}は ${n}の倍数。` }; }
    const n = pick([12, 18, 24, 36, 20, 30]); const divs = []; for (let i = 1; i <= n; i++) if (n % i === 0) divs.push(i); const good = pick(divs.filter(d => d > 1 && d < n)); let bad1 = good + 1; while (n % bad1 === 0) bad1++; let bad2 = good + 3; while (n % bad2 === 0 || bad2 === bad1) bad2++; let bad3 = good + 5; while (n % bad3 === 0 || bad3 === bad1 || bad3 === bad2) bad3++;
    return { q: `${n}の約数は どれ？`, t: 'choice', c: shuffle([good, bad1, bad2, bad3].map(String)), a: String(good), e: `${n}÷${good}=${n / good} で わり切れるから ${good}は 約数だよ。` };
  },
  frac_diff(lv) { const pairs = [[2, 3], [2, 5], [3, 4], [3, 5], [4, 5], [2, 7], [3, 7]]; const [d1, d2] = pick(pairs); const n1 = ri(1, d1 - 1), n2 = ri(1, d2 - 1); const L = d1 * d2; const num = n1 * d2 + n2 * d1; if (num >= L) return GEN.frac_diff(lv); return { q: `${n1}/${d1} + ${n2}/${d2} = ？（約分して「3/5」のように 書こう）`, t: 'input', a: fracStr(num, L), e: `通分すると ${n1 * d2}/${L}+${n2 * d1}/${L}=${num}/${L}${fracStr(num, L) !== `${num}/${L}` ? `。約分して ${fracStr(num, L)}` : ''}。` }; },
  average(lv) { const n = ri(3, 4); const vals = Array.from({ length: n }, () => ri(2, 12)); const sum = vals.reduce((s, v) => s + v, 0); if (sum % n !== 0) return GEN.average(lv); return { q: `${vals.join('、')} の 平均は？`, t: 'input', a: String(sum / n), e: `合計${sum}÷個数${n}=${sum / n}。` }; },
  ratio(lv) { const base = pick([200, 400, 500, 800, 1000]); const p = pick([10, 20, 25, 30, 40, 50, 60, 70, 80]); return { q: `${base}円の ${p}% は 何円？`, t: 'input', a: String(base * p / 100), e: `${p}%=${p / 100}。${base}×${p / 100}=${base * p / 100}円。` }; },
  area_tri(lv) { const shapes = [() => { const b = ri(4, 12), h = ri(2, 10); if ((b * h) % 2) return null; return { q: `底辺${b}cm、高さ${h}cmの 三角形の 面積は？（数だけ・cm²）`, a: b * h / 2, e: `${b}×${h}÷2=${b * h / 2}cm²。` }; }, () => { const b = ri(3, 12), h = ri(2, 10); return { q: `底辺${b}cm、高さ${h}cmの 平行四辺形の 面積は？（数だけ・cm²）`, a: b * h, e: `${b}×${h}=${b * h}cm²。` }; }]; let r = null; while (!r) r = pick(shapes)(); return { q: r.q, t: 'input', a: String(r.a), e: r.e }; },
  frac_mul(lv) { const a = ri(1, 4), b = ri(2, 5), c = ri(1, 4), d = ri(2, 5); if (Math.random() < 0.5) return { q: `${a}/${b} × ${c}/${d} = ？（約分して 答えよう）`, t: 'input', a: fracStr(a * c, b * d), e: `分子どうし・分母どうしを かけて ${a * c}/${b * d}=${fracStr(a * c, b * d)}。` }; return { q: `${a}/${b} ÷ ${c}/${d} = ？（約分して 答えよう）`, t: 'input', a: fracStr(a * d, b * c), e: `わる数を 逆数にして ${a}/${b}×${d}/${c}=${fracStr(a * d, b * c)}。` }; },
  algebra(lv) { const x = ri(2, 12), b = ri(1, 15); if (Math.random() < 0.5) return { q: `x + ${b} = ${x + b} の とき、x = ？`, t: 'input', a: String(x), e: `${x + b}−${b}=${x}。` }; const a = ri(2, 9); return { q: `${a} × x = ${a * x} の とき、x = ？`, t: 'input', a: String(x), e: `${a * x}÷${a}=${x}。` }; },
  hi(lv) { const a = ri(2, 6), b = ri(2, 6); const k = ri(2, 5); return { q: `${a} : ${b} = ${a * k} : x の とき、x = ？`, t: 'input', a: String(b * k), e: `${a}を ${k}倍して ${a * k}。だから ${b}も ${k}倍して ${b * k}。` }; },
  circle(lv) { const r = ri(2, 10); if (Math.random() < 0.5) return { q: `半径${r}cmの 円の 面積は？（数だけ・cm²）`, t: 'input', a: String(Math.round(r * r * 3.14 * 100) / 100), e: `${r}×${r}×3.14=${Math.round(r * r * 3.14 * 100) / 100}cm²。` }; return { q: `直径${r * 2}cmの 円の 円周は？（数だけ・cm）`, t: 'input', a: String(Math.round(r * 2 * 3.14 * 100) / 100), e: `円周=直径×3.14=${r * 2}×3.14=${Math.round(r * 2 * 3.14 * 100) / 100}cm。` }; },
  speed(lv) { const v = pick([40, 50, 60, 80, 4, 5, 12]); const t = ri(2, 5); const unit = v > 20 ? 'km' : 'km'; const mode = ri(0, 2); if (mode === 0) return { q: `時速${v}kmで ${t}時間 進むと 何km？`, t: 'input', a: String(v * t), e: `道のり=速さ×時間=${v}×${t}=${v * t}km。` }; if (mode === 1) return { q: `${v * t}kmを ${t}時間で 進んだ ときの 時速は？（数だけ・km）`, t: 'input', a: String(v), e: `速さ=道のり÷時間=${v * t}÷${t}=時速${v}km。` }; return { q: `時速${v}kmで ${v * t}km 進むのに かかる 時間は？（数だけ・時間）`, t: 'input', a: String(t), e: `時間=道のり÷速さ=${v * t}÷${v}=${t}時間。` }; },
  prop(lv) { const k = ri(2, 8); const x = ri(2, 9); if (Math.random() < 0.5) return { q: `yは xに 比例し、x=1の とき y=${k}。x=${x}の とき y=？`, t: 'input', a: String(k * x), e: `y=${k}×x。x=${x}なら y=${k * x}。` }; const A = k * x; return { q: `yは xに 反比例し、x=1の とき y=${A}。x=${x}の とき y=？`, t: 'input', a: String(k), e: `y=${A}÷x。x=${x}なら y=${k}。` }; },
};

/* ---------- 問題セット組み立て ---------- */
function kanjiQuestion(list) {
  const [word, yomi] = pick(list);
  const seen = new Set([yomi]);
  const wrong = [];
  for (const p of shuffle(list)) {
    if (!seen.has(p[1])) { seen.add(p[1]); wrong.push(p[1]); }
    if (wrong.length === 3) break;
  }
  return { q: `「${word}」の 読み方は？`, t: 'choice', c: shuffle([yomi, ...wrong]), a: yomi, e: `「${word}」は「${yomi}」と 読むよ。` };
}
function vocabQuestion(list) {
  if (Math.random() < 0.5) {
    const [en, ja] = pick(list);
    const wrong = shuffle(list.filter(p => p[1] !== ja)).slice(0, 3).map(p => p[1]);
    return { q: `「${en}」の 意味は？`, t: 'choice', c: shuffle([ja, ...wrong]), a: ja, e: `${en} = ${ja} だよ。` };
  }
  const [en, ja] = pick(list);
  const wrong = shuffle(list.filter(p => p[0] !== en)).slice(0, 3).map(p => p[0]);
  return { q: `「${ja}」を 英語で 言うと？`, t: 'choice', c: shuffle([en, ...wrong]), a: en, e: `${ja} = ${en} だよ。` };
}

// unit定義(curriculum.js)を受け取り、n問の出題セットを返す
function buildQuestions(unit, n, level, opts) {
  opts = opts || {};
  const out = [];
  const seen = new Set();
  let guard = 0;
  while (out.length < n && guard++ < n * 30) {
    let q = null;
    if (unit.gen && GEN[unit.gen]) q = GEN[unit.gen](level || 2);
    else if (unit.kanji && KANJI[unit.kanji]) q = kanjiQuestion(KANJI[unit.kanji]);
    else if (unit.vocab && VOCAB[unit.vocab]) q = vocabQuestion(VOCAB[unit.vocab]);
    else if (unit.pool && POOLS[unit.pool]) {
      const pool = shuffle(POOLS[unit.pool]);
      q = pool.find(p => !seen.has(p.q)) || null;
      // 固定プールは定義順のままだと正解が先頭に固定されるため、選択肢を必ずシャッフルする
      if (q) q = Object.assign({ t: 'choice' }, q, q.c ? { c: shuffle(q.c) } : {});
    }
    if (!q) break;
    if (seen.has(q.q)) continue;
    seen.add(q.q);
    // 支援モード: 選択肢を2つに減らす
    if (opts.reduceChoices && q.t === 'choice' && q.c.length > 2) {
      const wrong = q.c.filter(x => x !== q.a);
      q.c = shuffle([q.a, wrong[0]]);
    }
    out.push(q);
  }
  return shuffle(out); // Fisher–Yatesで出題順ランダム
}

module.exports = { buildQuestions, KANJI, VOCAB, POOLS, GEN };
